mapper.select:
SELECT /* @SQLID=SUB00_01-06_1#Sql002 */ SBP.* FROM ( SELECT COUNT(*) OVER() AS TOTAL_ROW, LPAD(A.SBP_NO, 6, '0') AS SBP_NO, NVL (A.ANS_UPDATE_TIME, A.UPDATE_TIME) AS ANS_UPDATE_TIME, A.CREATE_TIME AS REGISTER_DATE, A.TITLE AS TITLE, A.CATEGORY AS CATEGORY, A.STATUS AS STATUS FROM CORDYS.SUG_BOX_PERSONAL A
A.CREATE_USER = #{req.userId} AND TO_DATE(TO_CHAR(A.CREATE_TIME, 'yyyy/mm/dd'), 'yyyy/mm/dd') BETWEEN TO_DATE(#{req.registerDateFrom}, 'yyyy/mm/dd') AND TO_DATE(#{req.registerDateTo}, 'yyyy/mm/dd')
AND A.STATUS = #{req.status}
AND A.TITLE LIKE '%' || #{req.title} || '%'
ORDER BY A.SBP_NO ) SBP WHERE ROWNUM <= #{req.maxRow}

SELECT /* @SQLID=SUB00_01-06_1#Sql003 */ SBP.* FROM ( SELECT COUNT(*) OVER() AS TOTAL_ROW, LPAD(A.SBP_NO, 6, '0') AS SBP_NO, NVL (A.ANS_UPDATE_TIME, A.UPDATE_TIME) AS ANS_UPDATE_TIME, A.CREATE_TIME AS REGISTER_DATE, A.BROKER_CODE AS BROKER_CODE, B.BRANCH_NAME AS BROKER_NAME, A.INTERMEDIARY_EMP_CD AS EMP_CODE, C.USER_NM AS EMP_NAME, A.TITLE AS TITLE, A.CATEGORY AS CATEGORY, A.STATUS AS STATUS, A.SUGGESTION AS SUGGESTION FROM CORDYS.SUG_BOX_PERSONAL A LEFT JOIN CORDYS.MEDIATE_BRANCH B ON A.BROKER_CODE = B.BROKER_CODE AND B.BROKER_BRANCH_KIND = '00' LEFT JOIN CORDYS.TB_MED_USERS C ON A.CREATE_USER = C.USER_ID
TO_DATE(TO_CHAR(A.CREATE_TIME, 'yyyy/mm/dd'), 'yyyy/mm/dd') BETWEEN TO_DATE(#{req.registerDateFrom}, 'yyyy/mm/dd') AND TO_DATE(#{req.registerDateTo}, 'yyyy/mm/dd')
AND A.STATUS = #{req.status}
AND A.TITLE LIKE '%' || #{req.title} || '%'
AND B.BRANCH_NAME LIKE '%' || #{req.brokerName} || '%'
AND B.BROKER_CODE = #{req.brokerCode}
ORDER BY A.SBP_NO ) SBP WHERE ROWNUM <= #{req.maxRow}
